/**
 * @summary List admin audit logs
 */
export const getGetAdminAuditLogsUrl = (params?: GetAdminAuditLogsParams) => {
  const normalizedParams = new URLSearchParams();

  Object.entries(params || {}).forEach(([key, value]) => {
    if (value !== undefined) {
      normalizedParams.append(key, value === null ? "null" : value.toString());
    }
  });

  const stringifiedParams = normalizedParams.toString();

  return stringifiedParams.length > 0
    ? `/api/admin/audit-logs?${stringifiedParams}`
    : `/api/admin/audit-logs`;
};

export const getAdminAuditLogs = async (
  params?: GetAdminAuditLogsParams,
  options?: RequestInit,
): Promise<PaginatedAdminAuditLog> => {
  return customFetch<PaginatedAdminAuditLog>(getGetAdminAuditLogsUrl(params), {
    ...options,
    method: "GET",
  });
};

